"use client";

import React, { useState, useEffect, Suspense } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { generatePalettes, Palette } from "@/lib/palette";
import { decodePaletteUrl, encodePaletteUrl, PaletteType } from "@/lib/url";
import { PaletteGrid } from "@/components/PaletteGrid";
import { Controls } from "@/components/Controls";
import { PaletteRow } from "@/components/PaletteRow";
import { ExportPanel } from "@/components/ExportPanel";

function PaletteContent() {
  const searchParams = useSearchParams();
  const router = useRouter();

  // Initial state from URL or defaults
  const decoded = decodePaletteUrl(searchParams);
  
  const [baseColor, setBaseColor] = useState(decoded.baseHex || "#3B82F6");
  const [activeType, setActiveType] = useState<PaletteType>(decoded.type || "monochromatic");
  const [palettes, setPalettes] = useState<Palette[]>([]);
  const [pageUrl, setPageUrl] = useState("");

  // Update palettes whenever base color changes
  useEffect(() => {
    const cleanHex = baseColor.startsWith('#') ? baseColor.slice(1) : baseColor;
    if (/^[0-9A-F]{6}$/i.test(cleanHex)) {
      const formattedHex = `#${cleanHex}`;
      const generated = generatePalettes(formattedHex);
      setPalettes(generated);
      
      // Update URL
      const queryString = encodePaletteUrl(formattedHex, activeType);
      router.replace(queryString, { scroll: false });
    }
  }, [baseColor, activeType, router]);

  // Handle browser URL for sharing
  useEffect(() => {
    if (typeof window !== "undefined") {
      setPageUrl(window.location.href);
    }
  }, [baseColor, activeType]);

  const activePalette = palettes.find((p) => p.type === activeType) || palettes[0];

  return (
    <div className="max-w-5xl w-full flex flex-col gap-8">
      <header className="mb-4">
        <div className="flex items-center justify-between mb-2">
          <h1 className="text-4xl font-black tracking-tight text-brand-slate-900">
            Palette<span className="text-brand-rose-500">Forge</span>
          </h1>
          <div className="flex items-center gap-2 text-sm font-medium text-brand-slate-500 bg-brand-slate-100 px-3 py-1 rounded-full">
            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
            Live Engine v1.0
          </div>
        </div>
        <p className="text-brand-slate-600 max-w-lg">
          Generate premium color schemes instantly. Built for designers who demand precision and accessibility.
        </p>
      </header>

      <Controls 
        baseColor={baseColor} 
        setBaseColor={setBaseColor} 
        paletteType={activeType}
        pageUrl={pageUrl}
      />

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in fade-in slide-in-from-bottom-8 duration-1000">
        {/* Left: Active Palette Detail */}
        <div className="lg:col-span-12">
          {activePalette && (
            <div className="mb-8">
              <h2 className="text-xs font-black uppercase tracking-[0.2em] text-brand-slate-400 mb-6 flex items-center gap-4">
                Selected Palette
                <div className="h-px bg-brand-slate-200 flex-grow" />
              </h2>
              <PaletteGrid palette={activePalette} />
            </div>
          )}
          
          {activePalette && (
            <div className="mb-8">
              <h2 className="text-xs font-black uppercase tracking-[0.2em] text-brand-slate-400 mb-6 flex items-center gap-4">
                Developer Export
                <div className="h-px bg-brand-slate-200 flex-grow" />
              </h2>
              <ExportPanel palette={activePalette} />
            </div>
          )}
        </div>

        {/* List of all palettes as rows */}
        <div className="lg:col-span-12">
          <h2 className="text-xs font-black uppercase tracking-[0.2em] text-brand-slate-400 mb-6 flex items-center gap-4">
            Variation Library
            <div className="h-px bg-brand-slate-200 flex-grow" />
          </h2>
          <div className="flex flex-col gap-3 bg-white p-3 rounded-2xl border border-brand-slate-100 shadow-sm">
            {palettes.map((palette) => (
              <PaletteRow 
                key={palette.type} 
                palette={palette} 
                isActive={activeType === palette.type}
                onSelectAction={() => setActiveType(palette.type as PaletteType)}
              />
            ))}
          </div>
        </div>
      </div>

      <footer className="mt-16 pt-8 border-t border-brand-slate-100 text-center text-brand-slate-400 text-sm pb-12">
        <p>© 2026 PaletteForge Engine. All rights reserved.</p>
        <p className="mt-1">Built with Next.js, Tailwind 4, and Chroma-js.</p>
      </footer>
    </div>
  );
}

export default function Home() {
  return (
    <main className="flex min-h-screen flex-col items-center p-8 md:p-16 lg:p-24 bg-brand-slate-50">
      <Suspense fallback={
        <div className="flex items-center justify-center h-screen">
          <div className="w-12 h-12 border-4 border-brand-rose-200 border-t-brand-rose-500 rounded-full animate-spin" />
        </div>
      }>
        <PaletteContent />
      </Suspense>
    </main>
  );
}
